//#region src/index.ts
const rightTrimRe = /=$/;
function extractorSvelte() {
	return {
		name: "svelte",
		order: 100,
		extract({ id, extracted }) {
			if (id && id.endsWith(".svelte")) Array.from(extracted).forEach((r) => {
				if (r.startsWith("class:")) {
					extracted.add(r.slice(6).replace(rightTrimRe, ""));
					extracted.delete(r);
				}
			});
		}
	};
}
//#endregion
export { extractorSvelte as default };
